SELECT COUNT(*)
FROM app_lorebook_entry
WHERE character_id = #{characterId}

SELECT *
FROM app_lorebook_entry
WHERE character_id = #{characterId}
ORDER BY priority DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT character_id AS characterId, COUNT(*) AS totalCount, SUM(CASE WHEN source_type = 'embedded_character_book' THEN 1 ELSE 0 END) AS embeddedCount, SUM(CASE WHEN source_type != 'embedded_character_book' OR source_type IS NULL THEN 1 ELSE 0 END) AS manualCount, SUM(CASE WHEN enabled = 1 THEN 1 ELSE 0 END) AS enabledCount FROM app_lorebook_entry WHERE character_id IN
#{characterId}
GROUP BY character_id

